"""Base classes and interfaces for neuroimaging data structures.

This module provides abstract base classes that define the common interfaces
for neuroimaging data structures, mirroring the neuroim2 R package hierarchy.
"""

from abc import ABC, abstractmethod
from typing import Tuple, Optional, Union, Any, List
import numpy as np
from numpy.typing import NDArray, ArrayLike
import attrs


@attrs.define
class NeuroSpace:
    """Defines the spatial properties of neuroimaging data.

    This class encapsulates the geometric and spatial information about
    a neuroimaging volume, including dimensions, voxel spacing, origin,
    and coordinate transformations.

    Attributes:
        dims: Shape of the volume (x, y, z) or (x, y, z, t)
        spacing: Voxel dimensions in mm (default 1mm isotropic)
        origin: Coordinate of the first voxel (default 0, 0, 0)
        axes: Axis labels (default ["i", "j", "k"]) 
        trans: 4x4 transformation matrix to world coordinates
    """
    dims: Tuple[int, ...] = attrs.field(validator=attrs.validators.instance_of(tuple))
    spacing: Tuple[float, ...] = attrs.field(
        default=(1.0, 1.0, 1.0),
        validator=attrs.validators.instance_of(tuple)
    )
    origin: Tuple[float, ...] = attrs.field(
        default=(0.0, 0.0, 0.0),
        validator=attrs.validators.instance_of(tuple)
    )
    axes: List[str] = attrs.field(
        factory=lambda: ["i", "j", "k"],
        validator=attrs.validators.instance_of(list)
    )
    trans: Optional[NDArray[np.float64]] = attrs.field(
        default=None,
        validator=attrs.validators.optional(attrs.validators.instance_of(np.ndarray))
    )

    def __attrs_post_init__(self) -> None:
        """Validate dimensions match after initialization."""
        n_dims = len(self.dims)
        if n_dims < 3:
            raise ValueError(f"dims must have at least 3 dimensions, got {n_dims}")

        if len(self.spacing) == 3 and n_dims == 4:
            # Add time dimension spacing if missing
            self.spacing = self.spacing + (1.0,)
        elif len(self.spacing) != n_dims:
            raise ValueError(f"spacing length ({len(self.spacing)}) must match dims length ({n_dims})")

        if len(self.origin) != 3:
            raise ValueError(f"origin must have exactly 3 values, got {len(self.origin)}")

        if self.trans is None:
            # Create default transformation matrix
            self.trans = np.eye(4, dtype=np.float64)
            self.trans[0, 0] = self.spacing[0]
            self.trans[1, 1] = self.spacing[1]
            self.trans[2, 2] = self.spacing[2]
            self.trans[0:3, 3] = self.origin

    @property
    def n_dims(self) -> int:
        """Number of dimensions."""
        return len(self.dims)

    @property
    def spatial_dims(self) -> Tuple[int, int, int]:
        """First three (spatial) dimensions."""
        return self.dims[:3]

    @property
    def n_voxels(self) -> int:
        """Total number of voxels in the spatial dimensions."""
        return int(np.prod(self.spatial_dims))


class ArrayLike3D(ABC):
    """Abstract interface for 3D array-like neuroimaging objects."""

    @abstractmethod
    def __getitem__(self, key: Any) -> NDArray:
        """Array-style indexing for data access."""
        pass

    @abstractmethod
    def __setitem__(self, key: Any, value: ArrayLike) -> None:
        """Array-style indexing for data assignment."""
        pass

    @property
    @abstractmethod
    def shape(self) -> Tuple[int, int, int]:
        """Shape of the 3D array."""
        pass

    @property
    @abstractmethod
    def dtype(self) -> np.dtype:
        """Data type of the array elements."""
        pass


class ArrayLike4D(ABC):
    """Abstract interface for 4D array-like neuroimaging objects."""

    @abstractmethod
    def __getitem__(self, key: Any) -> NDArray:
        """Array-style indexing for data access."""
        pass

    @abstractmethod
    def __setitem__(self, key: Any, value: ArrayLike) -> None:
        """Array-style indexing for data assignment."""
        pass

    @property
    @abstractmethod  
    def shape(self) -> Tuple[int, int, int, int]:
        """Shape of the 4D array."""
        pass

    @property
    @abstractmethod
    def dtype(self) -> np.dtype:
        """Data type of the array elements."""
        pass


class NeuroVol(ArrayLike3D):
    """Base class for 3D brain volumes.

    This abstract class defines the interface for 3D neuroimaging volumes,
    providing common functionality for spatial operations and data access.
    """

    def __init__(self, space: NeuroSpace):
        """Initialize with spatial information.

        Args:
            space: NeuroSpace object defining the volume geometry
        """
        if space.n_dims != 3:
            raise ValueError(f"NeuroVol requires 3D space, got {space.n_dims}D")
        self.space = space

    @property
    def shape(self) -> Tuple[int, int, int]:
        """Shape of the volume."""
        return self.space.spatial_dims

    def indices(self) -> Tuple[NDArray[np.int32], NDArray[np.int32], NDArray[np.int32]]:
        """Get the indices of all voxels as a meshgrid.

        Returns:
            Tuple of 3D arrays containing x, y, z indices
        """
        return np.meshgrid(
            np.arange(self.shape[0]),
            np.arange(self.shape[1]),
            np.arange(self.shape[2]),
            indexing='ij'
        )

    def coords(self) -> Tuple[NDArray[np.float64], NDArray[np.float64], NDArray[np.float64]]:
        """Get the world coordinates of all voxels.

        Returns:
            Tuple of 3D arrays containing x, y, z world coordinates
        """
        indices = self.indices()
        # Apply transformation matrix to get world coordinates
        coords = np.stack(indices + (np.ones_like(indices[0]),), axis=-1)
        world_coords = np.tensordot(coords, self.space.trans.T, axes=1)
        return world_coords[..., 0], world_coords[..., 1], world_coords[..., 2]


class NeuroVec(ArrayLike4D):
    """Base class for 4D brain image time series.

    This abstract class defines the interface for 4D neuroimaging data,
    typically representing 3D volumes over time.
    """

    def __init__(self, space: NeuroSpace):
        """Initialize with spatial information.

        Args:
            space: NeuroSpace object defining the 4D geometry
        """
        if space.n_dims != 4:
            raise ValueError(f"NeuroVec requires 4D space, got {space.n_dims}D")
        self.space = space

    @property
    def shape(self) -> Tuple[int, int, int, int]:
        """Shape of the 4D array."""
        return self.space.dims[:4]

    @property
    def n_volumes(self) -> int:
        """Number of volumes (time points)."""
        return self.space.dims[3]

    @abstractmethod
    def series(self, indices: ArrayLike) -> NDArray:
        """Extract time series for specified voxels.

        Args:
            indices: Voxel indices (can be various formats)

        Returns:
            Array of shape (n_timepoints, n_voxels)
        """
        pass


class LogicalNeuroVol(NeuroVol):
    """Boolean 3D brain mask.

    Represents a binary mask indicating regions of interest in the brain.
    """

    def __init__(self, data: NDArray[np.bool_], space: NeuroSpace):
        """Initialize with boolean data and spatial information.

        Args:
            data: 3D boolean array
            space: NeuroSpace object defining the volume geometry
        """
        super().__init__(space)
        if data.shape != self.shape:
            raise ValueError(f"Data shape {data.shape} doesn't match space dims {self.shape}")
        self._data = data.astype(np.bool_)

    @property
    def dtype(self) -> np.dtype:
        """Data type is always bool."""
        return np.dtype(np.bool_)

    def __getitem__(self, key: Any) -> NDArray[np.bool_]:
        """Get mask values."""
        return self._data[key]

    def __setitem__(self, key: Any, value: ArrayLike) -> None:
        """Set mask values."""
        self._data[key] = value

    def indices(self, mask_value: bool = True) -> Tuple[NDArray[np.int32], ...]:
        """Get indices where mask equals specified value.

        Args:
            mask_value: Value to search for (default True)

        Returns:
            Tuple of arrays containing indices where mask == mask_value
        """
        return np.where(self._data == mask_value)

    @property
    def n_true(self) -> int:
        """Number of True voxels in the mask."""
        return int(np.sum(self._data))


class ClusteredNeuroVol(NeuroVol):
    """3D volume with cluster assignments.

    Represents a parcellation or clustering of brain voxels, where each
    voxel is assigned to a cluster ID.
    """

    def __init__(self, clusters: NDArray[np.int32], mask: LogicalNeuroVol, 
                 space: NeuroSpace):
        """Initialize with cluster assignments.

        Args:
            clusters: 1D array of cluster IDs for masked voxels
            mask: Boolean mask indicating valid voxels
            space: NeuroSpace object defining the volume geometry
        """
        super().__init__(space)
        self.mask = mask
        self.clusters = clusters

        if len(clusters) != mask.n_true:
            raise ValueError(
                f"Number of clusters ({len(clusters)}) must match "
                f"number of True voxels in mask ({mask.n_true})"
            )

    @property
    def dtype(self) -> np.dtype:
        """Data type of cluster IDs."""
        return self.clusters.dtype

    @property
    def n_clusters(self) -> int:
        """Number of unique clusters."""
        return len(np.unique(self.clusters))

    @property
    def cluster_ids(self) -> NDArray[np.int32]:
        """Unique cluster IDs."""
        return np.unique(self.clusters)

    def __getitem__(self, key: Any) -> NDArray[np.int32]:
        """Get cluster assignments for voxels."""
        # Create full volume with -1 for non-mask voxels
        vol = np.full(self.shape, -1, dtype=np.int32)
        vol[self.mask.indices()] = self.clusters
        return vol[key]

    def __setitem__(self, key: Any, value: ArrayLike) -> None:
        """Not implemented for clustered volumes."""
        raise NotImplementedError("Cannot modify cluster assignments directly")

