"""Base classes and interfaces for HDF5-based neuroimaging data structures.

This module extends pyneuroim's base classes to provide HDF5 storage capabilities.
"""

from abc import ABC, abstractmethod
from typing import Tuple, Optional, Union, Any, List, ContextManager
import numpy as np
from numpy.typing import NDArray, ArrayLike
import h5py

# Import base classes from pyneuroim
from pyneuroim import (
    NeuroSpace,
    NeuroVol,
    NeuroVec,
    LogicalNeuroVol as PyNeuroImLogicalNeuroVol,
    ClusteredNeuroVol as PyNeuroImClusteredNeuroVol,
)

# Re-export pyneuroim classes for convenience
__all__ = [
    'NeuroSpace',
    'NeuroVol', 
    'NeuroVec',
    'LogicalNeuroVol',
    'ClusteredNeuroVol',
    'H5ArrayLike3D',
    'H5ArrayLike4D',
]


# Create aliases for backward compatibility
LogicalNeuroVol = PyNeuroImLogicalNeuroVol
ClusteredNeuroVol = PyNeuroImClusteredNeuroVol


class H5ArrayLike3D(ABC):
    """Abstract interface for HDF5-backed 3D array-like neuroimaging objects."""

    @abstractmethod
    def __getitem__(self, key: Any) -> NDArray:
        """Array-style indexing for data access from HDF5."""
        pass

    @abstractmethod
    def __setitem__(self, key: Any, value: ArrayLike) -> None:
        """Array-style indexing for data assignment to HDF5."""
        pass

    @property
    @abstractmethod
    def shape(self) -> Tuple[int, int, int]:
        """Shape of the 3D array."""
        pass

    @property
    @abstractmethod
    def dtype(self) -> np.dtype:
        """Data type of the array."""
        pass

    @abstractmethod
    def close(self) -> None:
        """Close the HDF5 file handle."""
        pass

    @abstractmethod
    def __enter__(self) -> 'H5ArrayLike3D':
        """Context manager entry."""
        pass

    @abstractmethod
    def __exit__(self, exc_type, exc_val, exc_tb) -> None:
        """Context manager exit."""
        pass


class H5ArrayLike4D(ABC):
    """Abstract interface for HDF5-backed 4D array-like neuroimaging objects."""

    @abstractmethod
    def __getitem__(self, key: Any) -> NDArray:
        """Array-style indexing for data access from HDF5."""
        pass

    @abstractmethod
    def __setitem__(self, key: Any, value: ArrayLike) -> None:
        """Array-style indexing for data assignment to HDF5."""
        pass

    @property
    @abstractmethod
    def shape(self) -> Tuple[int, int, int, int]:
        """Shape of the 4D array."""
        pass

    @property
    @abstractmethod
    def dtype(self) -> np.dtype:
        """Data type of the array."""
        pass

    @abstractmethod
    def close(self) -> None:
        """Close the HDF5 file handle."""
        pass

    @abstractmethod
    def __enter__(self) -> 'H5ArrayLike4D':
        """Context manager entry."""
        pass

    @abstractmethod
    def __exit__(self, exc_type, exc_val, exc_tb) -> None:
        """Context manager exit."""
        pass

